Here is an existing Python module that handles user authentication. It works but has several problems: it mixes concerns, has no separation between storage and logic, uses globals, and is hard to test. Refactor it into clean, testable code.

```python
import hashlib
import json
import os
import time

USERS_FILE = "users.json"
SESSIONS = {}
MAX_ATTEMPTS = 5
LOCKOUT_TIME = 300
failed_attempts = {}

def load_users():
    if os.path.exists(USERS_FILE):
        with open(USERS_FILE) as f:
            return json.load(f)
    return {}

def save_users(users):
    with open(USERS_FILE, 'w') as f:
        json.dump(users, f)

def hash_password(password):
    return hashlib.sha256(password.encode()).hexdigest()

def register(username, password, email):
    users = load_users()
    if username in users:
        return {"error": "Username already exists"}
    if len(password) < 8:
        return {"error": "Password must be at least 8 characters"}
    users[username] = {
        "password": hash_password(password),
        "email": email,
        "created_at": time.time()
    }
    save_users(users)
    return {"success": True}

def login(username, password):
    if username in failed_attempts:
        attempts, lockout_time = failed_attempts[username]
        if attempts >= MAX_ATTEMPTS and time.time() - lockout_time < LOCKOUT_TIME:
            return {"error": "Account locked. Try again later."}
    users = load_users()
    if username not in users:
        return {"error": "Invalid credentials"}
    if users[username]["password"] != hash_password(password):
        if username not in failed_attempts:
            failed_attempts[username] = [0, time.time()]
        failed_attempts[username][0] += 1
        failed_attempts[username][1] = time.time()
        return {"error": "Invalid credentials"}
    failed_attempts.pop(username, None)
    import uuid
    token = str(uuid.uuid4())
    SESSIONS[token] = {"username": username, "created_at": time.time()}
    return {"token": token}

def get_current_user(token):
    if token not in SESSIONS:
        return None
    session = SESSIONS[token]
    if time.time() - session["created_at"] > 3600:
        del SESSIONS[token]
        return None
    return session["username"]

def logout(token):
    if token in SESSIONS:
        del SESSIONS[token]
        return True
    return False

def change_password(token, old_password, new_password):
    username = get_current_user(token)
    if not username:
        return {"error": "Not authenticated"}
    users = load_users()
    if users[username]["password"] != hash_password(old_password):
        return {"error": "Wrong password"}
    if len(new_password) < 8:
        return {"error": "Password must be at least 8 characters"}
    users[username]["password"] = hash_password(new_password)
    save_users(users)
    return {"success": True}
```

Refactor this code with the following goals:
1. Separate concerns: split into UserRepository (storage), AuthService (business logic), and SessionManager
2. Use dependency injection so each class receives its dependencies (no globals, no hardcoded file paths)
3. Add proper password hashing (explain why SHA-256 is insufficient and what to use instead)
4. Make it fully testable — show how you'd write a test for the login flow using a mock repository
5. Keep the same public API behavior

Provide the complete refactored code and explain the key decisions you made.
